insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('dbaf948f-8172-4bef-a00e-0c6992aaedae', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'COREangels Porto', 'angel_network', 'Porto', 'PT', '{"Portugal"}', 'https://coreangels.com', false, 'coreangels.com', false, 'pre_seed', 'seed', 50000, 500000, '{"generalist"}', null, 'medium_high', 1, 'Local + coachable; pitch what the syndicate’s angels get to help with (institutional B2B rollout in Greater Porto), not just the cheque.', 'Route the opportunity internally — one coordinated approach.', 'COREangels Porto contact form', 'form', 'Publicly states valuations below €5M; our ask is €7–10M pre-money.', 'open', 'David Alves can route internally to Terry Huang (COREangels Health Ventures). One coordinated approach, not two cold ones.', null, null, 'not_contacted', null, null);
insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('ea4b68f1-35d2-420b-a029-528d9c80ca70', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'COREangels Health Ventures', 'angel_network', null, 'PT', '{"Europe"}', null, false, null, false, 'pre_seed', 'seed', null, null, '{"healthtech"}', null, 'medium_high', 2, 'Health-focused angel group; route via David Alves (COREangels Porto).', 'An internal referral from David Alves.', null, 'unknown', null, 'not_applicable', 'Gregor Hoffman co-leads with Terry Huang — do not contact both cold.', null, null, 'not_contacted', null, null);
insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('030e5195-e6b5-4a49-ac0e-eae42c502c00', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'Nina Capital', 'vc', 'Barcelona', 'ES', '{"Europe"}', 'https://nina.capital', true, 'nina.capital', true, 'pre_seed', 'seed', 500000, 1500000, '{"healthtech","digital health"}', 'Biodesign — “deep understanding of the NEED is the DNA of every great invention.” “We’re not anti-AI. We’re anti-bullshit healthtech.” 400+ startups/quarter; they start with a deck and questions by email on purpose.', 'high', 2, 'Lead with the NEED, not the tech — adherence to preventive monitoring is what every wearable fails at. Frame the pilot as clinical validation, not growth.', 'Submit deck via dealflow@, then a short LinkedIn note referencing the submission.', 'dealflow@nina.capital', 'email', null, 'not_applicable', null, null, null, 'not_contacted', null, null);
insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('f5928973-fcfa-41dd-af6b-176b8bd3e462', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'Calm/Storm Ventures', 'vc', 'Vienna', 'AT', '{"Europe"}', 'https://calmstorm.vc', true, 'calmstorm.vc', true, 'pre_seed', 'seed', 25000, 250000, '{"taboo health","digital health"}', '#tabootech; ~100 portfolio companies incl. chronic constipation.', 'high', 2, 'The toilet is the most taboo data source in health — which is exactly why nobody built it. The taboo is the moat, not the obstacle.', 'Join the round as co-investor (signal + network play). Never ask them to lead.', 'https://calmstorm.vc/pitch', 'form', 'Co-invests only, never leads a full round — needs a lead alongside.', 'open', 'Polagnoli built Speedinvest’s health team — these funds’ people know each other; keep messaging consistent.', null, null, 'not_contacted', null, null);
insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('dd4ef882-db55-4e25-a32d-f731ab48d033', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'Crista Galli Ventures', 'family_office', 'London', 'UK', '{"Europe"}', 'https://cristagalli.com', true, 'ipqcap.com', true, 'seed', 'series_a', 500000, 2000000, '{"healthtech","deeptech healthcare","techbio"}', '“From liquid biopsies to digital biomarkers, we can diagnose earlier & monitor continuously outside hospital.” “Salutogenesis instead of pathogenesis.” “As a Family Office, we think in decades, not quarters.” “We are physician scientists before investors.” Looks for: scientific differentiation · exceptional founders · meaningful patient impact · a deep understanding of healthcare.', 'high', 2, 'Continuous passive longitudinal sampling vs. the episodic clinic snapshot. Evergreen = patient capital through a hardware timeline — say so. Address “deep understanding of healthcare” explicitly.', 'Submit to pitch@ipqcap.com first, then a LinkedIn note referencing the submission.', 'pitch@ipqcap.com', 'email', null, 'not_applicable', null, null, null, 'not_contacted', null, null);
insert into entities (id, org_id, name, type, hq_city, hq_country, invests_in_geographies, website, website_verified, email_domain, email_domain_verified, stage_min, stage_max, check_min_eur, check_max_eur, sectors, thesis, fit_score, wave, our_angle, the_ask, submission_channel, submission_channel_type, hard_filter, hard_filter_status, network_cluster_notes, interest_eur, contact_lock_until, status, dormant_since, dormant_reason) values ('a24a8b27-56bc-4eb4-a224-9b2c2355285a', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'Speedinvest Health', 'vc', 'Vienna', 'AT', '{"Europe"}', 'https://speedinvest.com', false, 'speedinvest.com', true, 'pre_seed', 'seed', 500000, 1500000, '{"healthtech"}', null, 'high', 2, 'Elvie analogue: device + companion app + a category nobody discussed. Zitna personally lived that scaling problem — say it explicitly.', 'A first conversation on the seed.', null, 'unknown', null, 'not_applicable', 'Polagnoli (Calm/Storm) built Speedinvest’s health team — keep messaging consistent across both.', null, null, 'not_contacted', null, null);
