insert into people (id, org_id, entity_id, full_name, role, seniority_rank, based_in, linkedin_url, linkedin_verified, email_verified, email_guess, email_guess_confidence, email_source, bounce_count, phone, background, personal_notes, linked_companies, linked_funds, hook, hook_status, kill_words, watch_outs, preferred_language, intro_path, data_source, privacy_notice_sent, do_not_contact) values ('e97f6c71-ed8d-44bd-a524-74c38898f3a7', 'bca54499-03c8-469b-a48d-b9f442e44f69', 'dd4ef882-db55-4e25-a32d-f731ab48d033', 'Dr. Fiona Pathiraja', 'Founding Partner', 1, 'London / Copenhagen', 'https://www.linkedin.com/in/fionapathiraja', true, null, 'f.pathiraja@ipqcap.com', 'medium', 'pattern guess', 0, null, 'Dual board-certified in Clinical Radiology and Public Health; ex-UCLH consultant radiologist; DoH policy advisor. Evergreen structure.', null, '{"Vitrue Health","UCLH"}', '{"Crista Galli Ventures","IPQ Capital"}', 'Their thesis is “salutogenesis instead of pathogenesis” — their own word for prevention. She is a diagnostician; ablute_ is a diagnostic instrument disguised as a bathroom fixture.', 'researched', '{"wellness","AI-led framing"}', 'LinkedIn Influencer with high inbound — a generic message dies. Evergreen = patient through a hardware timeline; say so. Use “salutogenesis” instead of the kill word.', 'en', null, 'cristagalli.com (fetched 21 Jul 2026) + LinkedIn', false, false);
